from cmu_graphics import *

# code in this file generated by Claude with edits made by me

# ============================================================
# SHARED BACKGROUND - call this in every screen's draw function
# ============================================================
def drawPokerTableBackground(app):
    # Dark wood border
    drawRect(0, 0, app.width, app.height, fill=rgb(45, 28, 16))
    
    # Green felt table
    drawRect(40, 40, app.width - 80, app.height - 80, 
             fill=rgb(30, 100, 50), border=rgb(60, 40, 20), 
             borderWidth=6)
    
    # Inner gold trim
    drawRect(52, 52, app.width - 104, app.height - 104, 
             fill=None, border=rgb(180, 140, 60), borderWidth=2)
    
    # Corner decorations
    corners = [(60, 60), (app.width - 68, 60), 
               (60, app.height - 68), (app.width - 68, app.height - 68)]
    for cx, cy in corners:
        drawPixelDiamond(cx, cy, rgb(180, 140, 60))

def drawPixelDiamond(x, y, color):
    # 8-bit style diamond made of small squares
    drawRect(x + 4, y, 4, 4, fill=color)       # top
    drawRect(x, y + 4, 4, 4, fill=color)       # left
    drawRect(x + 4, y + 4, 4, 4, fill=color)   # center
    drawRect(x + 8, y + 4, 4, 4, fill=color)   # right
    drawRect(x + 4, y + 8, 4, 4, fill=color)   # bottom


# ============================================================
# 8-BIT TEXT RENDERING
# ============================================================
def drawPixelText(text, centerX, centerY, color, scale=1):
    # Uses cmu_graphics built-in text but with a blocky font style
    # For true 8-bit feel, we draw a shadow behind the text
    shadowOffset = max(2, 2 * scale)
    
    # Shadow
    drawLabel(text, centerX + shadowOffset, centerY + shadowOffset, 
              size=16 * scale, bold=True, fill=rgb(0, 0, 0), opacity=50,
              font='monospace')
    # Main text
    drawLabel(text, centerX, centerY, 
              size=16 * scale, bold=True, fill=color,
              font='monospace')


# ============================================================
# DECORATIVE CARD SPRITES (8-bit style mini cards)
# ============================================================
def drawMiniCard(x, y, suit):
    drawRect(x, y, 22, 30, fill='white', border=rgb(60,60,60), borderWidth=1)
    symbols = {'heart': '♥', 'diamond': '♦', 'spade': '♠', 'club': '♣'}
    colors = {'heart': 'red', 'diamond': 'red', 'spade': 'black', 'club': 'black'}
    drawLabel(symbols[suit], x + 11, y + 15, size=18, fill=colors[suit], bold=True)


# ============================================================
# MENU SCREEN
# ============================================================
def drawMenuScreen(app):
    drawPokerTableBackground(app)
    
    # Title banner background (pixelated banner shape)
    drawRect(120, 100, 560, 60, fill=rgb(140, 20, 20))
    drawRect(124, 104, 552, 52, fill=rgb(180, 30, 30))
    # Pixel border effect on banner
    drawRect(120, 100, 560, 4, fill=rgb(200, 160, 50))
    drawRect(120, 156, 560, 4, fill=rgb(200, 160, 50))
    drawRect(120, 100, 4, 60, fill=rgb(200, 160, 50))
    drawRect(676, 100, 4, 60, fill=rgb(200, 160, 50))
    
    # Title text
    drawPixelText('WELCOME TO CARD GAME SUITE', app.width / 2, 130, 
                  rgb(255, 230, 150), scale=1.5)
    
    # Subtitle
    drawPixelText('please select a game below!', app.width / 2, 195, 
                  rgb(200, 200, 180), scale=1)
    
    # Decorative chip icons next to subtitle
    drawPixelChip(app.width/2 - 180, 188, rgb(200, 50, 50))
    drawPixelChip(app.width/2 + 168, 188, rgb(50, 50, 200))

    # Decorative cards scattered around the title
    drawMiniCard(135, 115, 'heart')
    drawMiniCard(165, 115, 'spade')
    drawMiniCard(605, 115, 'diamond')
    drawMiniCard(635, 115, 'club')
    
    # Footer text
    drawPixelText('press R for rules', app.width / 2, 535, 
                  rgb(150, 150, 130), scale=0.8)
    
    # Decorative bottom cards
    # Bottom left
    drawMiniCard(80, 480, 'club')
    drawMiniCard(110, 490, 'heart')

    # Bottom right (mirrored)
    drawMiniCard(app.width - 132, 490, 'diamond')
    drawMiniCard(app.width - 102, 480, 'spade')

def drawPixelChip(x, y, color):
    # Simple 8-bit poker chip (circle made of squares)
    drawRect(x + 4, y, 8, 4, fill=color)
    drawRect(x, y + 4, 16, 8, fill=color)
    drawRect(x + 4, y + 12, 8, 4, fill=color)
    # Center dot
    drawRect(x + 6, y + 6, 4, 4, fill='white')